import { z } from 'zod';
import { ok } from '@agentcash/neverthrow';

import { safeFetchJson } from '@/shared/neverthrow/fetch';
import { getBaseUrl } from '@/shared/utils';
import { MCP_VERSION } from '@/shared/version';

import type { Address } from 'viem';

/**
 * Error report input
 */
export interface ErrorReportInput {
  tool: string;
  summary: string;
  errorMessage: string;
  resource?: string;
  stack?: string;
  fullReport?: string;
}

/**
 * Submit an error report to agentcash telemetry.
 */
export async function submitErrorReport(
  surface: string,
  input: ErrorReportInput,
  address: Address,
  dev: boolean
) {
  const telemetryResult = await safeFetchJson(
    surface,
    new Request(`${getBaseUrl(dev)}/api/telemetry`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        tool: input.tool,
        summary: input.summary,
        errorMessage: input.errorMessage,
        resource: input.resource,
        stack: input.stack,
        fullReport: input.fullReport,
        walletAddress: address,
        mcpVersion: MCP_VERSION,
        reportedAt: new Date().toISOString(),
      }),
    }),
    z.object({
      reportId: z.string(),
    })
  );

  if (telemetryResult.isErr()) {
    return telemetryResult;
  }

  const { reportId } = telemetryResult.value;

  return ok({
    submitted: true,
    reportId,
    message:
      'Error report submitted successfully. The agentcash team will investigate.',
  });
}
